/**
 * @summary Search traceability records
 */
export const getSearchTraceabilityUrl = (params?: SearchTraceabilityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/traceability/search?${stringifiedParams}`
    : `/api/traceability/search`;
};

export const searchTraceability = async (
  params?: SearchTraceabilityParams,
  options?: RequestInit,
): Promise<TraceSearchResult[]> => {
  return customFetch<TraceSearchResult[]>(getSearchTraceabilityUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchTraceabilityQueryKey = (
  params?: SearchTraceabilityParams,
) => {
  return [`/api/traceability/search`, ...(params ? [params] : [])] as const;
};

export const getSearchTraceabilityQueryOptions = <
  TData = Awaited<ReturnType<typeof searchTraceability>>,
  TError = ErrorType<unknown>,
>(
  params?: SearchTraceabilityParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchTraceability>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getSearchTraceabilityQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof searchTraceability>>
  > = ({ signal }) => searchTraceability(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof searchTraceability>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type SearchTraceabilityQueryResult = NonNullable<
  Awaited<ReturnType<typeof searchTraceability>>
>;
export type SearchTraceabilityQueryError = ErrorType<unknown>;

/**
 * @summary Search traceability records
 */

export function useSearchTraceability<
  TData = Awaited<ReturnType<typeof searchTraceability>>,
  TError = ErrorType<unknown>,
>(
  params?: SearchTraceabilityParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchTraceability>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getSearchTraceabilityQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
